import React, { useState, useRef } from "react";
import Sidebar from "../components/Sidebar";
import { analysisAPI } from "../services/api";

export default function ResumeMatch() {

  const fileRef = useRef(null);

  const [file,setFile] = useState(null);
  const [skills,setSkills] = useState([]);
  const [jobs,setJobs] = useState([]);
  const [loading,setLoading] = useState(false);
  const [error,setError] = useState("");
  const [step,setStep] = useState("upload");

  const handleFile = (e)=>{
    const f = e.target.files[0];
    if(!f) return;
    setFile(f);
    setError("");
  };

  const analyze = async ()=>{

    if(!file){
      setError("Upload resume first");
      return;
    }

    setLoading(true);
    setError("");

    try{

      const res = await analysisAPI.resume(file);

      const extractedSkills =
        res.data.skills ||
        res.data.detected_skills ||
        [];

      setSkills(extractedSkills);

      if(extractedSkills.length === 0){
        setError("No skills detected in resume");
        setLoading(false);
        return;
      }

      const jobsRes = await analysisAPI.matchJobs(extractedSkills);

      const predictions =
        jobsRes.data.predictions ||
        jobsRes.data.jobs ||
        jobsRes.data.matches ||
        [];

      setJobs(predictions);
      setStep("results");

    }catch(err){

      console.error(err);

      setError(
        err.response?.data?.detail ||
        "Server error while analysing resume"
      );

    }finally{
      setLoading(false);
    }

  };

  const reset = ()=>{
    setFile(null);
    setSkills([]);
    setJobs([]);
    setStep("upload");
    setError("");
  };

  return (

<div style={{marginLeft:"220px",padding:"2rem"}}>

<Sidebar/>

<h2>📄 Resume Job Match</h2>

{step==="upload" && (

<div>

<input
type="file"
accept=".pdf,.png,.jpg,.jpeg"
ref={fileRef}
onChange={handleFile}
/>

<br/><br/>

<button
onClick={analyze}
disabled={loading}
>

{loading ? "Analysing..." : "Analyse Resume"}

</button>

{error && (
<p style={{color:"red"}}>
⚠️ {error}
</p>
)}

</div>

)}

{step==="results" && (

<div>

<button onClick={reset}>
Upload New Resume
</button>

<h3>
Detected Skills ({skills.length})
</h3>

<div>

{skills.map((s,i)=>(
<span
key={i}
style={{
padding:"5px 10px",
background:"#38e29a",
margin:"5px",
borderRadius:"6px",
display:"inline-block"
}}
>
{s}
</span>
))}

</div>

<br/>

<h3>
Best Job Matches
</h3>

{jobs.length===0 && (
<p>No job matches found</p>
)}

{jobs.map((job,i)=>{

const score =
job.match_percentage ||
job.match_score ||
job.similarity ||
0;

return(

<div
key={i}
style={{
border:"1px solid #ddd",
padding:"15px",
marginBottom:"10px",
borderRadius:"8px"
}}
>

<h4>
{i+1}. {job.job_role}
</h4>

<p>
Department: {job.department}
</p>

<p>
Match Score: {score}%
</p>

{job.matching_skills && (

<p>
<strong>Matching Skills:</strong>
{" "}
{job.matching_skills.join(", ")}
</p>

)}

{job.missing_skills && (

<p>
<strong>Missing Skills:</strong>
{" "}
{job.missing_skills.join(", ")}
</p>

)}

</div>

);

})}

</div>

)}

</div>

  );

}
